'use client'
import {
  composeRefs,
  createMachine,
  useMachine,
  useSignal,
  useSignalEffect,
  useSignals,
} from '@cascivo/core'
import {
  cloneElement,
  useRef,
  type KeyboardEvent,
  type MouseEvent,
  type ReactElement,
  type ReactNode,
  type Ref,
} from 'react'
import styles from './dropdown.module.css'

const machine = createMachine({
  initial: 'closed' as const,
  states: {
    closed: { on: { OPEN: 'open' } },
    open: { on: { CLOSE: 'closed' } },
  },
})

export interface DropdownItem {
  label: string
  value: string
  icon?: ReactNode
  disabled?: boolean
  separator?: boolean
}

export interface DropdownProps {
  trigger: ReactElement
  items: DropdownItem[]
  onSelect?: (value: string) => void
  placement?: 'bottom-start' | 'bottom-end'
  open?: boolean
  onOpenChange?: (open: boolean) => void
}

export function Dropdown({
  trigger,
  items,
  onSelect,
  placement = 'bottom-start',
  open,
  onOpenChange,
}: DropdownProps) {
  useSignals()
  const [state, send] = useMachine(machine)
  const rootRef = useRef<HTMLDivElement>(null)
  const triggerRef = useRef<HTMLElement>(null)
  const menuRef = useRef<HTMLDivElement>(null)
  const itemRefs = useRef<(HTMLButtonElement | null)[]>([])
  const activeIndex = useSignal(-1)

  const isControlled = open !== undefined
  const isOpen = isControlled ? open : state.value === 'open'
  const openSignal = useSignal(isOpen)
  openSignal.value = isOpen

  const enabledIndexes = items
    .map((item, index) => ({ item, index }))
    .filter(({ item }) => !item.separator && !item.disabled)
    .map(({ index }) => index)

  const setOpen = (next: boolean) => {
    if (!isControlled) send(next ? 'OPEN' : 'CLOSE')
    onOpenChange?.(next)
  }

  // Move keyboard focus to the active item whenever it changes while open.
  useSignalEffect(() => {
    const index = activeIndex.value
    if (openSignal.value && index >= 0) {
      itemRefs.current[index]?.focus()
    }
  })

  // Reset / seed the active item as the menu opens and closes.
  useSignalEffect(() => {
    if (openSignal.value) {
      activeIndex.value = enabledIndexes[0] ?? -1
    } else {
      activeIndex.value = -1
    }
  })

  // Open/close the popover and sync light-dismiss (toggle event) back to state.
  useSignalEffect(() => {
    if (openSignal.value) {
      menuRef.current?.showPopover()
    } else {
      menuRef.current?.hidePopover()
    }
  })

  useSignalEffect(() => {
    const menu = menuRef.current
    if (!menu) return
    const handleToggle = (event: Event) => {
      const toggle = event as ToggleEvent
      if (toggle.newState === 'closed') setOpen(false)
    }
    menu.addEventListener('toggle', handleToggle)
    return () => menu.removeEventListener('toggle', handleToggle)
  })

  const selectAt = (index: number) => {
    const item = items[index]
    if (!item || item.separator || item.disabled) return
    onSelect?.(item.value)
    setOpen(false)
    triggerRef.current?.focus()
  }

  const moveActive = (delta: number) => {
    if (enabledIndexes.length === 0) return
    const current = enabledIndexes.indexOf(activeIndex.value)
    const next = (current + delta + enabledIndexes.length) % enabledIndexes.length
    activeIndex.value = enabledIndexes[next] ?? -1
  }

  const handleMenuKeyDown = (event: KeyboardEvent<HTMLDivElement>) => {
    switch (event.key) {
      case 'ArrowDown':
        event.preventDefault()
        moveActive(1)
        break
      case 'ArrowUp':
        event.preventDefault()
        moveActive(-1)
        break
      case 'Home':
        event.preventDefault()
        activeIndex.value = enabledIndexes[0] ?? -1
        break
      case 'End':
        event.preventDefault()
        activeIndex.value = enabledIndexes[enabledIndexes.length - 1] ?? -1
        break
      case 'Escape':
        event.preventDefault()
        setOpen(false)
        triggerRef.current?.focus()
        break
      case 'Enter':
      case ' ':
        event.preventDefault()
        selectAt(activeIndex.value)
        break
    }
  }

  const triggerEl = trigger as ReactElement<{
    ref?: Ref<HTMLElement>
    onClick?: (e: MouseEvent) => void
  }>
  const renderedTrigger = cloneElement(triggerEl, {
    ref: composeRefs(triggerRef, triggerEl.props.ref),
    onClick: (event: MouseEvent) => {
      triggerEl.props.onClick?.(event)
      setOpen(!isOpen)
    },
    'aria-haspopup': 'menu',
    'aria-expanded': isOpen,
  } as Record<string, unknown>)

  return (
    <div ref={rootRef} className={styles['root']}>
      {renderedTrigger}
      <div
        ref={menuRef}
        popover="auto"
        role="menu"
        data-placement={placement}
        data-state={isOpen ? 'open' : 'closed'}
        className={styles['menu']}
        onKeyDown={handleMenuKeyDown}
      >
        {items.map((item, index) =>
          item.separator ? (
            <div key={`sep-${index}`} role="separator" className={styles['separator']} />
          ) : (
            <button
              key={item.value}
              type="button"
              role="menuitem"
              ref={(el) => {
                itemRefs.current[index] = el
              }}
              tabIndex={activeIndex.value === index ? 0 : -1}
              disabled={item.disabled}
              className={styles['item']}
              onClick={() => selectAt(index)}
            >
              {item.icon && (
                <span className={styles['icon']} aria-hidden="true">
                  {item.icon}
                </span>
              )}
              {item.label}
            </button>
          ),
        )}
      </div>
    </div>
  )
}

@layer cascivo.component {
  .root {
    position: relative;
    display: inline-flex;
  }

  .menu {
    position: absolute;
    inset-block-start: calc(100% + var(--cascivo-space-1));
    z-index: var(--cascivo-z-dropdown);
    min-inline-size: 10rem;
    max-inline-size: calc(100vw - var(--cascivo-space-4, 1rem));
    padding: var(--cascivo-space-1);
    background-color: var(--cascivo-color-surface-overlay);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-overlay);
    opacity: 0;
    visibility: hidden;
    translate: 0 -0.25rem;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter),
      visibility var(--cascivo-motion-enter);

    &[data-placement='bottom-start'] {
      inset-inline-start: 0;
    }
    &[data-placement='bottom-end'] {
      inset-inline-end: 0;
    }

    &[data-state='open'] {
      opacity: 1;
      visibility: visible;
      translate: 0 0;
    }

    @starting-style {
      &[data-state='open'] {
        opacity: 0;
        translate: 0 -0.25rem;
      }
    }
  }

  @supports (anchor-name: --a) and (position-anchor: --a) {
    .menu {
      position: fixed;
      inset: auto;
      position-anchor: var(--cascivo-dropdown-anchor, --dropdown-trigger);
    }

    .menu[data-placement='bottom-start'] {
      inset-area: block-end span-inline-start;
      inset-inline-start: 0;
    }

    .menu[data-placement='bottom-end'] {
      inset-area: block-end span-inline-end;
      inset-inline-end: 0;
    }

    @media (prefers-reduced-motion: no-preference) {
      .menu {
        transition:
          opacity var(--cascivo-motion-enter),
          translate var(--cascivo-motion-enter),
          visibility var(--cascivo-motion-enter),
          display var(--cascivo-motion-enter) allow-discrete,
          overlay var(--cascivo-motion-enter) allow-discrete;
      }

      @starting-style {
        .menu[data-state='open'] {
          opacity: 0;
          translate: 0 -0.25rem;
        }
      }
    }
  }

  .item {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    inline-size: 100%;
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    text-align: start;
    color: var(--cascivo-color-text);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-item);
    cursor: pointer;

    &:hover:not(:disabled),
    &:focus-visible {
      outline: none;
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .icon {
    display: inline-flex;
    align-items: center;
    color: var(--cascivo-color-text-muted);
  }

  .separator {
    block-size: 1px;
    margin-block: var(--cascivo-space-1);
    background-color: var(--cascivo-color-border);
  }
}

@media (forced-colors: active) {
  .menu {
    border: 1px solid ButtonText;
  }

  .item:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}
